import 'bootstrap/dist/css/bootstrap-grid.min.css';
import React, { useState, useEffect } from 'react';
import { BrowserRouter, Routes, Route, Link } from 'react-router-dom';
import Purchases from './pages/Purchases';
import AddVendor from './pages/AddVendor';
import Outflow from './pages/Outflow';
import MaterialList from './pages/MaterialList';

import ShoppingImage from './images/shopping.jpg';
import ShopImage from './images/shop.jpg';
import OutflowImage from './images/outflow.png';
import sumViewImage from './images/SUMView.png';

import './App.css'; // Import custom CSS for App component

function App() {

  const [materials, setMaterials] = useState([]);
  const [purchases, setPurchases] = useState([]);
  const [locations, setLocations] = useState([]);
  const [vendors, setVendors] = useState([]);


  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [materialResponse, purchaseResponse, locationResponse, vendorResponse] = await Promise.all([
        fetch('http://localhost:8081/materiallist').then((response) => response.json()),
        fetch('http://localhost:8081/PurchasesAPI').then((response) => response.json()),
        fetch('http://localhost:8081/LocationsAPI').then((response) => response.json()),
        fetch('http://localhost:8081/vendors').then((response) => response.json()),
      ]);

      setMaterials(materialResponse);
      setPurchases(purchaseResponse);
      setLocations(locationResponse);
      setVendors(vendorResponse);

    } catch (error) {
      console.log('Error fetching data:', error);
    }
  };



  return (
    <div className="App">
      <BrowserRouter>
        <header className="header">
          <h1 className="header-title">Robbie Inventories</h1>
          <nav className="navbar">
            <ul className="navbar-nav">
              <li className="nav-item">
                <Link to="/Purchases" className="nav-link">
                  <img src={ShoppingImage} alt="shopping" className="nav-image" />
                  <span>Inflow</span>
                </Link>
              </li>

              <li className="nav-item">
                <Link to="/Outflow" className="nav-link">
                  <img src={OutflowImage} alt="Outflow" className="nav-image" />
                  <span>Outflow</span>
                </Link>
              </li>

              <li className="nav-item">
                <Link to="/MaterialList" className="nav-link">
                  <img src={sumViewImage} alt="SUMView" className="nav-image" />
                  <span>Material List</span>
                </Link>
              </li>

              <li className="nav-item">
                <Link to="/AddVendor" className="nav-link">
                  <img src={ShopImage} alt="shop" className="nav-image" />
                  <span>Vendor List</span>
                </Link>
              </li>

            </ul>
          </nav>
        </header>
        <Routes>
          <Route path="/Purchases" element={<Purchases materials={materials} purchases={purchases} locations={locations} vendors={vendors} />} />
          <Route path="/Outflow" element={<Outflow />} />
          <Route path="/AddVendor" element={<AddVendor />} />
          <Route path="/MaterialList" element={<MaterialList materials={materials} setMaterials={setMaterials} />} />
          {/* Add other routes for different pages */}
        </Routes>
      </BrowserRouter>
    </div>
  );
}

export default App;
